/**
 * GameDataManagerComp.ts
 * Manages persisting and loading player-specific data.
 */

const { ccclass, property } = cc._decorator;

interface PlayerData {
    score: number;
    level: number;
    inventory: string[];
}

@ccclass
export class GameDataManagerComp extends cc.Component {

    // Runtime data (lost on reload)
    private _dataStore: { [key: string]: any } = {};

    // Persistent data (saved to localStorage)
    private _localData: { [key: string]: any } = {};

    private readonly STORAGE_KEY = "game_local_data";

    onLoad() {
        this.loadLocalData();
    }

    /**
     * Store runtime data (not saved to disk).
     */
    public setRuntimeData(key: string, value: any) {
        this._dataStore[key] = value;
    }

    public getRuntimeData<T>(key: string): T {
        return this._dataStore[key] as T;
    }

    /**
     * Store and save persistent data.
     */
    public setLocalData(key: string, value: any) {
        this._localData[key] = value;
        this.save();
    }

    public getLocalData<T>(key: string, defaultValue?: T): T {
        if (this._localData[key] === undefined) {
            return defaultValue;
        }
        return this._localData[key] as T;
    }

    private save() {
        cc.sys.localStorage.setItem(this.STORAGE_KEY, JSON.stringify(this._localData));
    }

    private loadLocalData() {
        const raw = cc.sys.localStorage.getItem(this.STORAGE_KEY);
        if (raw) {
            try {
                this._localData = JSON.parse(raw);
            } catch (e) {
                console.warn("Corrupted local data, resetting.");
                this._localData = {};
            }
        }
    }
}
