import { AssetManagerComp } from "./Declaration9999";
import { SlotConstants9999 } from "./slot/SlotConstants9999";
const { ESlotSymbol } = SlotConstants9999;
const { ccclass, property } = cc._decorator;

const configCoreSymbol = {
    [ESlotSymbol.H6]: "the_legend_of_musashi_symbol_h6_01",
    [ESlotSymbol.H5]: "the_legend_of_musashi_symbol_h5_01",
    [ESlotSymbol.H4]: "the_legend_of_musashi_symbol_h4_01",
    [ESlotSymbol.H3]: "the_legend_of_musashi_symbol_h3_01",
    [ESlotSymbol.H2]: "the_legend_of_musashi_symbol_h2_01",
    [ESlotSymbol.H1]: "the_legend_of_musashi_symbol_h1_01",
    [ESlotSymbol.L4]: "the_legend_of_musashi_symbol_L4_01",
    [ESlotSymbol.L3]: "the_legend_of_musashi_symbol_L3_01",
    [ESlotSymbol.L2]: "the_legend_of_musashi_symbol_L2_01",
    [ESlotSymbol.L1]: "the_legend_of_musashi_symbol_L1_01",

    [ESlotSymbol.SC]: "the_legend_of_musashi_symbol_scatter_01",
    [ESlotSymbol.WI]: "the_legend_of_musashi_symbol_wild_01",
    [ESlotSymbol.WI_LI]: "the_legend_of_musashi_symbol_wild_01",
    [ESlotSymbol.WI_EX]: "the_legend_of_musashi_symbol_wild_02",
};

@ccclass
export class AssetManager9999 extends AssetManagerComp {
    @property(cc.SpriteFrame) listCoreSymbols = [];

    public getCoreSymbolByCode(code) {
        const symbolName = configCoreSymbol[code];
        if (!symbolName) return null;
        return this.listCoreSymbols.find(sf => sf && sf.name === symbolName) || null;
    }

}