import { BasePopup, IPopupData } from "./BasePopup";
import type { IPopupOptions } from "../Managers/PopupManagerComp";

const { ccclass, property } = cc._decorator;

export interface ISelectPopupOptions extends IPopupData {
    title?: string;
    message?: string;
    textCancel?: string;
    textConfirm?: string;
    selectData?: any[];
    cbConfirm?: (selectData: any) => void;
    cbCancel?: () => void;
}

@ccclass
export class BaseSelectPopup extends BasePopup {

    @property(cc.Label)
    title: cc.Label = null;

    @property(cc.Label)
    message: cc.Label = null;

    @property(cc.Node)
    btnConfirm: cc.Node = null;

    @property(cc.Node)
    btnCancel: cc.Node = null;

    @property(cc.Node)
    selectItem: cc.Node = null;

    @property(cc.Node)
    selectHolder: cc.Node = null;

    private _cbConfirm: (selectData) => void = null;
    private _cbCancel: () => void = null;
    private _curSelect = null;
    private _isShowConfirm = false;
    onLoad() {
        super.onLoad();
        this.btnConfirm.on("click", this.onBtnConfirm, this);
        this.btnCancel.on("click", this.onBtnCancel, this);
    }

    show(options: IPopupOptions = {}) {
        super.show(options);
        this.setDataNotify(options.data);
    }

    private setDataNotify(data: ISelectPopupOptions) {
        this.resetDataNotify();
        const { title, message, textCancel, textConfirm, cbConfirm, cbCancel, selectData } = data;
        if (this.title && title) {
            this.title.string = title;
        }

        if (this.message && message) {
            this.message.string = message;
        }

        if (cbConfirm && textConfirm) {
            this._isShowConfirm = true;
            this._cbConfirm = cbConfirm;
            this.btnConfirm.active = true;
            this.btnConfirm.getComponentInChildren(cc.Label).string = textConfirm;
        }

        if (cbCancel && textCancel) {
            this._cbCancel = cbCancel;
            this.btnCancel.active = true;
            this.btnCancel.getComponentInChildren(cc.Label).string = textCancel;
        }
        this.setupSelect(selectData);
    }

    protected setupSelect(selectData: any[]) {
        if (selectData && selectData.length > 0) {
            this.selectHolder.removeAllChildren();
            selectData.forEach(item => {
                const node = cc.instantiate(this.selectItem);
                node.active = true;
                node.getComponent(cc.Toggle).isChecked = false;
                node.getComponentInChildren(cc.Label).string = item;
                node.on("toggle", () => {
                    this._curSelect = item;
                    this.btnConfirm.getComponent(cc.Button).interactable = !!this._curSelect;
                    if (!this._isShowConfirm) {
                        this.hide();
                    }
                }, this);
                this.selectHolder.addChild(node);
            });
        }
    }

    private resetDataNotify() {
        this.btnConfirm.getComponent(cc.Button).interactable = false;
        this._cbConfirm = null;
        this._cbCancel = null;
        this.title.string = "Notification";
        this.message.string = "";
        this.btnConfirm.active = false;
        this.btnCancel.active = false;
    }

    onBtnConfirm() {
        this.hide();
        this._cbConfirm?.(this._curSelect);
    }

    onBtnCancel() {
        this.hide();
        this._cbCancel?.();
    }
}
