/**
 * StateMachineComp.ts
 * A generic Finite State Machine component for Cocos Creator.
 * Attach to any node to manage states with automatic onUpdate calls.
 */

import { IState } from './IState';
import { SubjectComp } from '../Observer/SubjectComp';

const { ccclass, property } = cc._decorator;

@ccclass
export class StateMachineComp extends SubjectComp {

    private _states: Map<string, IState> = new Map();
    private _currentState: IState = null;
    private _previousState: IState = null;

    /**
     * Register a state. Must be added before it can be used.
     */
    public addState(state: IState): void {
        if (this._states.has(state.name)) {
            console.warn(`StateMachineComp: State '${state.name}' already registered, overwriting.`);
        }
        this._states.set(state.name, state);
    }

    /**
     * Register multiple states at once.
     */
    public addStates(states: IState[]): void {
        states.forEach(s => this.addState(s));
    }

    /**
     * Transition to a new state by name.
     * Calls onExit on current state, then onEnter on the new state.
     */
    public changeState(name: string): void {
        const nextState = this._states.get(name);
        if (!nextState) {
            console.warn(`StateMachineComp: State '${name}' not found.`);
            return;
        }

        if (this._currentState === nextState) return;

        if (this._currentState) {
            this._currentState.onExit();
        }

        this._previousState = this._currentState;
        this._currentState = nextState;
        this._currentState.onEnter();
    }

    /**
     * Return to the previous state (if any).
     */
    public revertState(): void {
        if (this._previousState) {
            this.changeState(this._previousState.name);
        }
    }

    /**
     * Get the currently active state.
     */
    public getCurrentState(): IState | null {
        return this._currentState;
    }

    /**
     * Get the name of the current state, or null.
     */
    public getCurrentStateName(): string | null {
        return this._currentState ? this._currentState.name : null;
    }

    /**
     * Check if the current state matches a given name.
     */
    public isInState(name: string): boolean {
        return this._currentState != null && this._currentState.name === name;
    }

    /**
     * Called every frame by Cocos. Delegates to current state's onUpdate.
     */
    update(dt: number): void {
        if (this._currentState) {
            this._currentState.onUpdate(dt);
        }
    }
}
