/**
 * ExampleCommand.ts
 * An example implementation of the Command pattern.
 * Could be used for player movement, etc.
 */

import { ICommand } from './ICommand';

export class ExampleCommand implements ICommand {
    private _target: cc.Node;
    private _previousPosition: cc.Vec3; // Position is Vec3 in Cocos 2.4+
    private _moveVector: cc.Vec3;

    constructor(target: cc.Node, moveVector: cc.Vec3) {
        this._target = target;
        this._moveVector = moveVector;
    }

    execute() {
        // Save current state for potential undo
        this._previousPosition = this._target.position; // .position returns a new Vec3 in 2.x usually, but let's be safe. 
        // Actually .position is a getter, returns a generic object sometimes or Vec3.
        // Best practice in 2.4 is to clone it.
        this._previousPosition = this._target.position.clone();
        
        // Execute the action (change state)
        this._target.x += this._moveVector.x;
        this._target.y += this._moveVector.y;
        // z is ignored in 2d mainly but good to keep consistency
        this._target.z += this._moveVector.z;

        console.log(`ExampleCommand Executed: Moved target by (${this._moveVector.x}, ${this._moveVector.y}).`);
    }

    undo() {
        if (this._previousPosition) {
            this._target.position = this._previousPosition;
            console.log(`ExampleCommand Undone: Restored position.`);
        }
    }
}
