import type { BasePopup } from "../Game/BasePopup";
export interface IPopupOptions {
    cbShow?: () => void;
    cbHide?: () => void;
    data?: any;
}
const { ccclass, property } = cc._decorator;

@ccclass
export class PopupManagerComp extends cc.Component {

    @property(cc.Node)
    popupContainer: cc.Node = null;

    @property(cc.Node)
    popupOverlay: cc.Node = null;


    @property([cc.Prefab])
    preloadedPopups: cc.Prefab[] = [];

    // Map of active popup instances: popupId -> Node
    private _activePopups: Map<string, BasePopup> = new Map();

    onLoad() {
        if (!this.popupContainer) {
            cc.warn("Pls attach popup container here: ", this.node);
        }
        this.preloadPopup();
        this.setOverlay(false);
    }

    private preloadPopup() {
        for (const prefab of this.preloadedPopups) {
            this.instantiatePopup(prefab);
        }
    }
    public showPopup(popupName: string, options: IPopupOptions = {}) {

        // Wrap cbHide to control overlay
        const originalCbHide = options.cbHide;
        options.cbHide = () => {
            originalCbHide?.();
            this.setOverlay(false);
        };

        this.setOverlay(true);

        if (this._activePopups.has(popupName)) {
            this.showActivePopup(popupName, options);
            return;
        }

        // Load dynamically
        this.loadPopup(popupName, options);
    }

    private showActivePopup(popupName: string, options: IPopupOptions = {}) {
        const popup = this._activePopups.get(popupName);
        popup.show(options);
    }

    private loadPopup(popupName: string, options: IPopupOptions = {}) {
        // Fallback if cc.resources is not immediately available

        cc.assetManager.loadBundle('preload', (err, bundle) => {
            if (err) {
                console.warn(`PopupManager: Failed to load popup ${popupName}`, err);
                return;
            }
            bundle.load(`popups/${popupName}`, cc.Prefab, (err, prefab: cc.Prefab) => {
                if (err) {
                    console.warn(`PopupManager: Failed to load popup ${popupName}`, err);
                    return;
                }
                this.instantiatePopup(prefab);
                this.showActivePopup(popupName, options);
            });
        });
    }

    /**
     * Hide a popup by type/ID.
     */
    public hidePopup(popupName: string) {
        if (this._activePopups.has(popupName)) {
            const popup = this._activePopups.get(popupName);
            popup.hide();
        }
    }

    private instantiatePopup(prefab: cc.Prefab) {
        const node = cc.instantiate(prefab);
        node.parent = this.popupContainer;
        const popupName = prefab.name;
        const popup = node.getComponent('BasePopup') as BasePopup;
        node.active = false;
        this._activePopups.set(popupName, popup);
        console.log(`PopupManager: Shown ${popupName}`);
    }

    private setOverlay(visible: boolean) {
        if (this.popupOverlay) {
            this.popupOverlay.active = visible;
        }
    }
}
