/**
 * Game API Service Plugin
 * Quản lý các kết nối API (Authenticate, Recover, Play, Complete) bằng Fetch.
 * Viết theo chuẩn ES6 Module, dễ dàng import vào Cocos Creator.
 */

const BASE_URL = 'https://demo.spinart.cloud';

export class GameAPI {
    private static _instance: GameAPI = null;

    public static get instance(): GameAPI {
        if (!this._instance) {
            this._instance = new GameAPI();
        }
        return this._instance;
    }

    private token: string = null;
    private sessionId: string = null;
    private defaultProvider: string = 'peterandsons';
    private defaultGame: string = 'musashi';

    constructor() {
        this.token = null;
        // Sinh ngẫu nhiên một x-session-id mới mỗi khi khởi tạo GameAPI
        this.sessionId = this._generateUUID();

        // Payload cố định cho game Musashi
        this.defaultProvider = 'peterandsons';
        this.defaultGame = 'musashi';
    }

    /**
     * Lưu trữ Token sau khi gọi Authen thành công
     * @param {string} token 
     */
    setToken(token) {
        this.token = token;
    }

    /**
     * Lấy token hiện tại
     * @returns {string|null} 
     */
    getToken() {
        return this.token;
    }

    /**
     * Helper tạo header chung cho các request
     * @param {boolean} requiresAuth - Cần attach Access Token hay không
     * @returns {object}
     */
    _getHeaders(requiresAuth = true) {
        const headers = {
            'accept': '*/*',
            'accept-language': 'en-US,en;q=0.9',
            'content-type': 'application/json',
            'x-session-id': this.sessionId
        };

        if (requiresAuth && this.token) {
            headers['authorization'] = `Bearer ${this.token}`;
        }

        return headers;
    }

    /**
     * Hàm gọi request nội bộ dạng POST
     * @param {string} endpoint 
     * @param {object} payload 
     * @param {boolean} requiresAuth 
     * @returns {Promise<any>}
     */
    async _post(endpoint, payload, requiresAuth = true) {
        const url = `${BASE_URL}${endpoint}`;

        try {
            const response = await fetch(url, {
                method: 'POST',
                headers: this._getHeaders(requiresAuth),
                body: JSON.stringify(payload)
            });

            if (!response.ok) {
                throw new Error(`[GameAPI] HTTP Error! Status: ${response.status} at ${endpoint}`);
            }

            return await response.json();
        } catch (error) {
            console.error(`[GameAPI] Fetch failed for ${endpoint}:`, error);
            throw error;
        }
    }

    /**
     * 1. API: Authenticate
     * Lấy JWT token để uỷ quyền các thao tác tiếp theo
     * @param {string} wallet Tên ví (mặc định: demo)
     * @param {string} operator Tên hệ thống (mặc định: demo)
     * @param {string} key Key cung cấp
     * @returns {Promise<any>}
     */
    async authenticate(wallet = 'demo', operator = 'demo', key = '343305068271') {
        const payload = {
            wallet,
            operator,
            key,
            provider: this.defaultProvider,
            game: this.defaultGame
        };

        const res = await this._post('/authenticate', payload, false);

        // Tự động lưu cache token nếu server có trả về
        if (res && res.token) {
            this.setToken(res.token);
        }
        return res;
    }

    /**
     * 2. API: Recover
     * Khôi phục trạng thái mạng cũ / Kiểm tra nếu ván trước chưa chốt (Complete)
     * Đẩy complete: false để hỏi server "tao còn nợ mảng anim nào chưa mở không?"
     * @param {boolean} complete 
     * @returns {Promise<any>}
     */
    async recover(complete = false) {
        const payload = {
            game: this.defaultGame,
            provider: this.defaultProvider,
            complete
        };

        return await this._post('/game/recover', payload, true);
    }

    /**
     * 3. API: Play / Spin
     * Quăng tiền, bắt đầu một vòng quay slot mới.
     * @param {number} bet Mức cược (mặc định 2)
     * @param {boolean} complete Để false nếu client tự lo render anim rồi Complete sau.
     * @param {boolean} asyncWin 
     * @returns {Promise<any>}
     */
    async play(bet = 2, complete = false, asyncWin = false) {
        const payload = {
            game: this.defaultGame,
            provider: this.defaultProvider,
            action: 'main',
            complete,
            asyncWin,
            bet
        };

        return await this._post('/game/play', payload, true);
    }

    /**
     * 4. API: Complete
     * Đóng ván! Báo cho server rớt nhịp xong rồi, cập nhật Balance mới nhất.
     * Thường gọi khi Anim nổ dây chuyền đã kết thúc 100%.
     * @param {string} roundId Lấy từ response lúc gọi /play
     * @param {boolean} asyncWin 
     * @returns {Promise<any>}
     */
    async complete(roundId, asyncWin = false) {
        const payload = {
            game: this.defaultGame,
            provider: this.defaultProvider,
            roundId, // Bắt buộc truyền roundId đúng
            asyncWin
        };

        return await this._post('/game/complete', payload, true);
    }

    /**
     * Sinh UUID V4 tạo x-session-id giả lập chuẩn
     * @returns {string}
     */
    _generateUUID() {
        return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
            const r = Math.random() * 16 | 0;
            const v = c === 'x' ? r : (r & 0x3 | 0x8);
            return v.toString(16);
        });
    }
}
