import { AssetManagerComp } from '../../Managers/AssetManagerComp';
import { EventManagerComp } from '../../Managers/EventManagerComp';
import { GameConfigManagerComp } from '../../Managers/GameConfigManagerComp';
import { GameDataManagerComp } from '../../Managers/GameDataManagerComp';
import { PopupManagerComp } from '../../Managers/PopupManagerComp';
import { PreloaderManagerComp } from '../../Managers/PreloaderManagerComp';
const { ccclass, property } = cc._decorator;

@ccclass
export class ObserverComp extends cc.Component {
    private _gameConfig: GameConfigManagerComp = null;
    private _assetManager: AssetManagerComp = null;
    private _popupManager: PopupManagerComp = null;
    private _gameDataManager: GameDataManagerComp = null;
    private _eventManager: EventManagerComp = null;
    private _preloaderManager: PreloaderManagerComp = null;
    onLoad() {
        this._gameConfig = this.node.getComponent(GameConfigManagerComp);
        this._assetManager = this.node.getComponent(AssetManagerComp);
        this._popupManager = this.node.getComponent(PopupManagerComp);
        this._gameDataManager = this.node.getComponent(GameDataManagerComp);
        this._eventManager = this.node.getComponent(EventManagerComp);
        this._preloaderManager = this.node.getComponent(PreloaderManagerComp);
    }

    public getConfig(): GameConfigManagerComp {
        return this._gameConfig;
    }

    public getAssetManager(): AssetManagerComp {
        return this._assetManager;
    }

    public getPopupManager(): PopupManagerComp {
        return this._popupManager;
    }

    public getGameDataManager(): GameDataManagerComp {
        return this._gameDataManager;
    }

    public getEventManager(): EventManagerComp {
        return this._eventManager;
    }
    public getPreloaderManager(): PreloaderManagerComp {
        return this._preloaderManager;
    }
}
