import type { IPopupOptions } from '../Managers/PopupManagerComp';
import { SubjectComp } from '../Patterns/Observer/SubjectComp';

export interface IPopupData { };
const { ccclass, property } = cc._decorator;
@ccclass
export class BasePopup extends SubjectComp {
    @property({ displayName: "Time show" })
    timeShow: number = 0.2;
    @property({ displayName: "Time hide" })
    timeHide: number = 0.2;
    @property({ displayName: "Time delay show" })
    timeDelayShow: number = 0;
    @property({ displayName: "Time delay hide" })
    timeDelayHide: number = 0;

    private _callbackShow: () => void = null;
    private _callbackHide: () => void = null;

    onLoad() {
        super.onLoad();
    }

    show(options: IPopupOptions = {}, data: IPopupData = {}) {
        const { cbShow, cbHide } = options;
        this._callbackShow = cbShow;
        this._callbackHide = cbHide;
        this.node.active = true;

        this.node.opacity = 0;
        cc.Tween.stopAllByTarget(this.node);
        cc.tween(this.node)
            .delay(this.timeDelayShow)
            .to(this.timeShow, { opacity: 255 })
            .call(() => {
                this._callbackShow?.();
                this.node.opacity = 255;
            })
            .start();
    }

    hide() {
        cc.Tween.stopAllByTarget(this.node);
        cc.tween(this.node)
            .delay(this.timeDelayHide)
            .to(this.timeHide, { opacity: 0 })
            .call(() => {
                this._callbackHide?.();
                this.node.active = false;
            })
            .start();
    }
}
