/**
 * EventManager.ts
 * A component-based EventManager. Instead of being a global singleton, 
 * this should be attached to a Node in the scene (e.g., a "Managers" node)
 * and referenced by others via the Inspector.
 */

const { ccclass, property } = cc._decorator;

@ccclass
export class EventManagerComp extends cc.Component {

    private _eventEmitter: cc.EventTarget = new cc.EventTarget();

    onLoad() {
        console.log("EventManagerComp initialized as a component instance.");
    }

    /**
     * Subscribe to an event.
     * @param eventName The name of the event.
     * @param callback The callback function.
     * @param target The target object (for 'this' context).
     */
    public on(eventName: string, callback: Function, target?: any) {
        this._eventEmitter.on(eventName, callback, target);
    }

    /**
     * Unsubscribe from an event.
     * @param eventName The name of the event.
     * @param callback The callback function.
     * @param target The target object.
     */
    public off(eventName: string, callback: Function, target?: any) {
        this._eventEmitter.off(eventName, callback, target);
    }

    /**
     * Emit an event.
     * @param eventName The name of the event.
     * @param args Arguments to pass to the event handler.
     */
    public emit(eventName: string, ...args: any[]) {
        this._eventEmitter.emit(eventName, ...args);
    }

    /**
     * Remove all listeners for a specific target.
     * @param target The target object to remove listeners for.
     */
    public targetOff(target: any) {
        this._eventEmitter.targetOff(target);
    }
}
