import { GameDataWriter } from "../DataModel/GameDataWriter";
import { NetworkManagerComp } from "../Managers/NetworkManagerComp";
import { SubjectComp } from "../Patterns/Observer/SubjectComp";
import { GameController } from "./GameController";
const { ccclass, property } = cc._decorator;

@ccclass
export class Director extends SubjectComp {
    @property(cc.Node) gameNode: cc.Node = null;

    _gameDataWriter: GameDataWriter;
    _gameController: GameController;
    async onLoad() {
        this.gameNode.active = false;
        await this.init();
    }

    private async init() {
        await this.initNetwork();
        await this.setupGame();
    }

    protected async setupGame() {
        this.initGameDataWriter();
        this.setupGameController();
        this.gameNode.active = true;
    }

    protected initGameDataWriter() {
        this._gameDataWriter = new GameDataWriter();
    }

    protected setupGameController() {
        this._gameController = this.gameNode.getComponent(GameController);
        this._gameController.setApiListener({
            callApiGetSession: this.callApiGetSession.bind(this),
            callApiGetSpinResult: this.callApiGetSpinResult.bind(this),
            calApiGetSpinComplete: this.calApiGetSpinComplete.bind(this),
            callApiSpinRestore: this.callApiSpinRestore.bind(this),
        })
    }

    private async initNetwork() {
        const response = await NetworkManagerComp.instance.authenticate();
        cc.log("Player authenticate:", response);
    }

    private executeScripts(scripts) {
        if (!scripts || !Array.isArray(scripts)) {
            return;
        }

        scripts.forEach(({ code, data }) => {
            cc.log("executeScript", code, data);
            this.gameNode.emit(code, data);
        })
    }

    public async callApiGetSession() {
        const response = await NetworkManagerComp.instance.callApiGetSession();
        this.executeScripts(this._gameDataWriter.makeScriptLastSession(response));
    }

    public async callApiGetSpinResult() {
        const response = await NetworkManagerComp.instance.callApiGetSpinResult();
        this.executeScripts(this._gameDataWriter.makeScriptSpinResult(response));
    }

    public async calApiGetSpinComplete(roundId: string) {
        const response = await NetworkManagerComp.instance.callApiGetSpinComplete(roundId);
        this.executeScripts(this._gameDataWriter.makeScriptSpinComplete(response));
    }

    public async callApiSpinRestore() {
        this.executeScripts(this._gameDataWriter.makeScriptRestoreSpinResult());
    }
}
