
const { ccclass, property } = cc._decorator;

@ccclass
export abstract class GameConfigManagerComp extends cc.Component {

    private mapConfig: Map<string, any> = new Map();

    protected onLoad(): void {
        this.setupConfig();
    }
    protected setupConfig() {
        const config = this.allConfig();
        Object.keys(config).forEach(key => {
            this.mapConfig.set(key, config[key]);
        });
    };

    private allConfig() {
        return {
            ...this.baseConfig(),
            ...this.gameConfig(),
        }
    }

    private baseConfig() {
        return {
            version: "1.0.0",
            debugMode: true,
        }
    }

    protected abstract gameConfig(): {};

    public getConfigByKey(key: string) {
        return this.mapConfig.get(key);
    }
}