/**
 * ExampleState.ts
 * Example implementations of IState for demonstration.
 *
 * Usage with StateMachineComp:
 *
 *   const sm = this.getComponent(StateMachineComp);
 *   sm.addStates([
 *       new IdleState(this.node),
 *       new MovingState(this.node, cc.v3(100, 0, 0)),
 *   ]);
 *   sm.changeState('Idle');
 */

import { IState } from './IState';

// ─── Idle State ──────────────────────────────────────────────

export class IdleState implements IState {
    name = 'Idle';
    private _target: cc.Node;

    constructor(target: cc.Node) {
        this._target = target;
    }

    onEnter(): void {
        console.log(`[IdleState] Enter — node '${this._target.name}' is now idle.`);
        // e.g. play idle animation
    }

    onUpdate(dt: number): void {
        // Idle logic per frame (e.g. check for input to transition)
    }

    onExit(): void {
        console.log(`[IdleState] Exit`);
    }
}

// ─── Moving State ────────────────────────────────────────────

export class MovingState implements IState {
    name = 'Moving';
    private _target: cc.Node;
    private _speed: number;
    private _direction: cc.Vec3;

    constructor(target: cc.Node, direction: cc.Vec3, speed: number = 200) {
        this._target = target;
        this._direction = direction.normalize();
        this._speed = speed;
    }

    onEnter(): void {
        console.log(`[MovingState] Enter — moving at speed ${this._speed}`);
        // e.g. play walk/run animation
    }

    onUpdate(dt: number): void {
        this._target.x += this._direction.x * this._speed * dt;
        this._target.y += this._direction.y * this._speed * dt;
    }

    onExit(): void {
        console.log(`[MovingState] Exit`);
        // e.g. stop animation
    }
}
